-- === market_daily_stats (58 rows) ===
DROP TABLE IF EXISTS `market_daily_stats`;
CREATE TABLE `market_daily_stats` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
  `limit_up` int DEFAULT NULL,
  `limit_down` int DEFAULT NULL,
  `suspended` int DEFAULT NULL,
  `turnover` decimal(15,2) DEFAULT NULL,
  `sh_up` int DEFAULT NULL,
  `sh_flat` int DEFAULT NULL,
  `sh_down` int DEFAULT NULL,
  `sz_up` int DEFAULT NULL,
  `sz_flat` int DEFAULT NULL,
  `sz_down` int DEFAULT NULL,
  `bj_up` int DEFAULT NULL,
  `bj_flat` int DEFAULT NULL,
  `bj_down` int DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_trade_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=89 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === fund_history (222 rows) ===
DROP TABLE IF EXISTS `fund_history`;
CREATE TABLE `fund_history` (
  `id` int NOT NULL AUTO_INCREMENT,
  `fund_code` varchar(10) DEFAULT NULL,
  `fund_name` varchar(100) DEFAULT NULL,
  `net_date` date DEFAULT NULL,
  `unit_nav` decimal(10,4) DEFAULT NULL,
  `accum_nav` decimal(10,4) DEFAULT NULL,
  `daily_growth` decimal(6,2) DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_fund_date` (`fund_code`,`net_date`)
) ENGINE=InnoDB AUTO_INCREMENT=388 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === market_sentiment (121 rows) ===
DROP TABLE IF EXISTS `market_sentiment`;
CREATE TABLE `market_sentiment` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
  `sentiment_value` decimal(5,2) DEFAULT NULL,
  `sentiment_zone` varchar(10) DEFAULT NULL,
  `market_desc` text,
  `week_day` varchar(10) DEFAULT NULL,
  `holiday_note` varchar(50) DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `composite_idx` decimal(6,4) DEFAULT NULL COMMENT 'original composite index',
  `calibrated` tinyint(1) DEFAULT '0' COMMENT '0=calc_sentiment, 1=calibrated',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_trade_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=364 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === market_capital_flow (123 rows) ===
DROP TABLE IF EXISTS `market_capital_flow`;
CREATE TABLE `market_capital_flow` (
  `trade_date` date NOT NULL,
  `main_force_net` decimal(15,2) DEFAULT NULL COMMENT 'main force net(yuan)',
  `retail_net` decimal(15,2) DEFAULT NULL COMMENT 'retail net(yuan)',
  `medium_net` decimal(15,2) DEFAULT NULL COMMENT 'medium order net(yuan)',
  `large_net` decimal(15,2) DEFAULT NULL COMMENT 'large order net(yuan)',
  `super_large_net` decimal(15,2) DEFAULT NULL COMMENT 'super large order net(yuan)',
  `main_force_pct` decimal(5,2) DEFAULT NULL,
  `retail_pct` decimal(5,2) DEFAULT NULL,
  `medium_pct` decimal(5,2) DEFAULT NULL,
  `large_pct` decimal(5,2) DEFAULT NULL,
  `super_large_pct` decimal(5,2) DEFAULT NULL,
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`trade_date`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === sentiment_raw_factors (122 rows) ===
DROP TABLE IF EXISTS `sentiment_raw_factors`;
CREATE TABLE `sentiment_raw_factors` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
  `composite_index` decimal(10,4) DEFAULT NULL COMMENT '4指数加权涨跌幅',
  `sector_up` int DEFAULT NULL COMMENT '行业板块上涨数',
  `sector_down` int DEFAULT NULL COMMENT '行业板块下跌数',
  `sector_ad_ratio` decimal(6,4) DEFAULT NULL COMMENT '板块涨跌比',
  `limit_up` int DEFAULT NULL,
  `limit_down` int DEFAULT NULL,
  `turnover` decimal(15,2) DEFAULT NULL COMMENT '成交额(亿)',
  `main_force_net` decimal(15,2) DEFAULT NULL COMMENT '主力净流入(万)',
  `volume_pctile_60d` decimal(5,2) DEFAULT NULL COMMENT '60日成交量百分位',
  `margin_balance` decimal(20,2) DEFAULT NULL COMMENT '融资融券余额(亿)',
  `northbound_net` decimal(15,2) DEFAULT NULL COMMENT '北向资金净流入(亿)',
  `sentiment_label` decimal(5,2) DEFAULT NULL COMMENT '聚类标签',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `trade_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=486 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === backtest_results (19 rows) ===
DROP TABLE IF EXISTS `backtest_results`;
CREATE TABLE `backtest_results` (
  `id` int NOT NULL AUTO_INCREMENT,
  `strategy_id` int NOT NULL,
  `fund_code` varchar(10) NOT NULL,
  `period_label` varchar(20) DEFAULT NULL,
  `initial_capital` decimal(12,2) DEFAULT NULL,
  `final_value` decimal(12,2) DEFAULT NULL,
  `total_return` decimal(8,2) DEFAULT NULL,
  `max_drawdown` decimal(8,2) DEFAULT NULL,
  `trade_count` int DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_sfp` (`strategy_id`,`fund_code`,`period_label`)
) ENGINE=InnoDB AUTO_INCREMENT=56 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === position (3 rows) ===
DROP TABLE IF EXISTS `position`;
CREATE TABLE `position` (
  `id` int NOT NULL AUTO_INCREMENT,
  `fund_code` varchar(10) NOT NULL,
  `fund_name` varchar(100) DEFAULT NULL,
  `trade_date` date NOT NULL,
  `trade_type` varchar(10) NOT NULL COMMENT 'buy/sell',
  `shares` int NOT NULL,
  `price` decimal(10,4) NOT NULL,
  `amount` decimal(12,2) NOT NULL,
  `shares_after` int NOT NULL,
  `cash_after` decimal(12,2) NOT NULL,
  `note` varchar(200) DEFAULT NULL,
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_fund` (`fund_code`),
  KEY `idx_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === strategy_signals (1 rows) ===
DROP TABLE IF EXISTS `strategy_signals`;
CREATE TABLE `strategy_signals` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
  `signal_type` varchar(10) NOT NULL COMMENT 'buyA/buyB/sell_all/stop_loss',
  `sentiment_value` decimal(5,2) DEFAULT NULL,
  `nav` decimal(10,4) DEFAULT NULL,
  `reason` varchar(200) DEFAULT NULL,
  `executed` tinyint(1) DEFAULT '0',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_date_type` (`trade_date`,`signal_type`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === etf_kline (969 rows) ===
DROP TABLE IF EXISTS `etf_kline`;
CREATE TABLE `etf_kline` (
  `id` int NOT NULL AUTO_INCREMENT,
  `fund_code` varchar(10) NOT NULL,
  `trade_date` date NOT NULL,
  `open` decimal(10,4) DEFAULT NULL,
  `high` decimal(10,4) DEFAULT NULL,
  `low` decimal(10,4) DEFAULT NULL,
  `close` decimal(10,4) DEFAULT NULL,
  `volume` decimal(20,2) DEFAULT NULL,
  `is_adj` tinyint(1) DEFAULT '1' COMMENT '1=前复权',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_fund_date` (`fund_code`,`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=3343 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


-- === index_daily (120 rows) ===
DROP TABLE IF EXISTS `index_daily`;
CREATE TABLE `index_daily` (
  `id` int NOT NULL AUTO_INCREMENT,
