  PRIMARY KEY (`id`),
  KEY `idx_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=899 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;


