-- === sector_fund_flow (0 rows) ===
DROP TABLE IF EXISTS `sector_fund_flow`;
CREATE TABLE `sector_fund_flow` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
