-- === northbound_flow (2264 rows) ===
DROP TABLE IF EXISTS `northbound_flow`;
CREATE TABLE `northbound_flow` (
  `id` int NOT NULL AUTO_INCREMENT,
  `trade_date` date NOT NULL,
  `net_buy` decimal(15,2) DEFAULT NULL COMMENT '当日成交净买额(亿)',
  `buy_amount` decimal(15,2) DEFAULT NULL COMMENT '买入成交额(亿)',
  `sell_amount` decimal(15,2) DEFAULT NULL COMMENT '卖出成交额(亿)',
  `cumulative_net` decimal(15,2) DEFAULT NULL COMMENT '历史累计净买额(亿)',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `trade_date` (`trade_date`)
) ENGINE=InnoDB AUTO_INCREMENT=4529 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

